insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:2-2-market-research:mcq:2d993385', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "What is not a secondary source of market research?", "options": ["Focus groups", "Internal business data", "Newspapers", "Websites"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — focus groups. Focus groups are a PRIMARY research method, not secondary. They involve selecting a small group of people to give their opinions on products. Internal business data (B), newspapers (C) and websites (D) are all examples of secondary (desk) research."}'::jsonb),
('business:2-2-market-research:mcq:42e4b653', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "A national retailer intends to trial a new product in some of its stores. Which of the following is NOT a benefit of trialling the product?", "options": ["It avoids wasting money on an unsuccessful national launch", "It helps identify the target market", "It requires a lot of national advertising and promotion", "It shows whether there is sufficient demand for the product"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — it requires a lot of national advertising and promotion. This is NOT a benefit — it is actually a drawback. One of the key advantages of trialling is that it is conducted on a small scale, avoiding expensive national advertising and promotion costs. Options A, B and D are all genuine benefits of trialling a product before a full national launch."}'::jsonb),
('business:2-2-market-research:mcq:500d6f9b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "Understanding customer needs is the main purpose of:", "options": ["Employee retention", "Innovation", "Market research", "The product lifecycle"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — market research. Market research is the collection of data on customer habits to help decision-making in marketing. Its main purpose is to understand customer needs — what they want, what they will pay, and whether they will buy a product. The other options are separate business concepts."}'::jsonb),
('business:2-2-market-research:mcq:1030e959', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "A focus group is an example of:", "options": ["A digital distribution channel", "A primary market research method", "Market segmentation", "Point of sale promotion"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — a primary market research method. A focus group is a carefully selected small group (around ten) of people who represent the target market. They are given information and asked questions. This is primary research because the data is collected first-hand for the specific needs of the business."}'::jsonb),
('business:2-2-market-research:tf:a58d435d', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Primary research is sometimes called ''desk research'' because it is carried out at a desk."}'::jsonb, '{"answer": false, "explain": "FALSE. Primary research is called ''FIELD research'' because the researcher goes out into the field to collect new, first-hand data. It is SECONDARY research that is called ''desk research'' — because it involves looking at data already collected by others, which can be done sitting at a desk."}'::jsonb),
('business:2-2-market-research:tf:966d52bf', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "A focus group of around ten people carefully selected to represent the target market is an example of primary research."}'::jsonb, '{"answer": true, "explain": "TRUE. A focus group is a primary research method because the data is collected first-hand directly from people. The group is selected to represent the target market and asked questions — generating new data specifically for the business''s needs."}'::jsonb),
('business:2-2-market-research:tf:53e7f28c', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "The census is an example of primary research because it collects data from every person in the country."}'::jsonb, '{"answer": false, "explain": "FALSE. The census is an example of SECONDARY research. Although the government collects new data every ten years, businesses USE this already-collected data for their own research purposes. Secondary research means data collected by someone else that a business then uses — it does not matter how the original data was gathered."}'::jsonb),
('business:2-2-market-research:tf:70842888', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Quantitative data is based on the opinions of consumers."}'::jsonb, '{"answer": false, "explain": "FALSE. Opinions are QUALITATIVE data. Quantitative data is based on facts and numbers — for example, the number of products sold or how often people eat cereals for breakfast. A helpful memory tip: QUALITATIVE = quality of opinions; QUANTITATIVE = quantity/numbers."}'::jsonb),
('business:2-2-market-research:tf:4108d7c5', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "One disadvantage of using questionnaires is that it is difficult to predict how many completed questionnaires will be returned."}'::jsonb, '{"answer": true, "explain": "TRUE. Response rates for questionnaires can be unpredictable. To increase returns, businesses may offer incentives such as an entry into a free prize draw. Low response rates can make the data less reliable or representative of the target market."}'::jsonb),
('business:2-2-market-research:tf:efe87789', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Secondary research is always cheaper than primary research."}'::jsonb, '{"answer": true, "explain": "TRUE — as a general rule. Because someone else has already completed the research, secondary research is usually much cheaper to collect than primary research. The cost of primary research comes from designing questions, paying interviewers, running focus groups, or setting up trials."}'::jsonb),
('business:2-2-market-research:tf:7c81b4e1', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Trialling a new product gives a business qualitative data about customer opinions on how to improve the product."}'::jsonb, '{"answer": false, "explain": "FALSE. This is a very common misconception! Trialling gives a business QUANTITATIVE data — specifically sales figures — to show whether there is demand for a product. It does NOT provide qualitative feedback about opinions. Do not confuse trialling with giving out free samples to gather opinions."}'::jsonb),
('business:2-2-market-research:tf:bee61061', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Internal data is a form of secondary research because it has already been collected within the business."}'::jsonb, '{"answer": true, "explain": "TRUE. Internal data — such as past sales figures, profits from departments, and customer comments — is a form of secondary research. It has already been collected for another purpose within the business. It has the advantage of being directly relevant to the business, unlike external secondary data."}'::jsonb),
('business:2-2-market-research:tf:4a99620b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "Small businesses will often undertake the same amount of market research as large businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. Smaller businesses may use very little, if any, market research. This is because market research — especially primary research — can be expensive and time-consuming. Small businesses are more likely to rely on secondary research or informal methods such as asking friends and family. Owners of small businesses may also rely on their own judgement."}'::jsonb),
('business:2-2-market-research:tf:c0607f3b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tf', 'tf', 1, '{"question": "An advantage of interviews over questionnaires is that the interviewer can explain questions if there is a misunderstanding."}'::jsonb, '{"answer": true, "explain": "TRUE. This is a key advantage of interviews. If a respondent does not understand a question, the interviewer can clarify it — this leads to more accurate data. With questionnaires, there is no one to explain unclear questions, which may lead to misunderstandings and unreliable answers."}'::jsonb),
('business:2-2-market-research:learn:09174ac5', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "What is Market Research?", "reading": "<p><strong>Market research</strong> is the collection of data on customer habits to help decision-making in marketing.</p>\n<p>Before a business starts, it is important that the owners check exactly who their customers are likely to be. Are they old or young, male or female, rich or poor? There is little point in starting a business and then wondering why you are not selling anything!</p>\n<p>This analysis of the market will normally be part of the <strong>business plan</strong> and it is an important part in setting up a successful business. Who a business aims its product or service at is called the <strong>target market</strong>. Understanding your target market is important because it can help a business <strong>segment</strong> its market — which means aiming different products at different groups of people.</p>\n<p><strong>Case study — Sarah''s Gourmet Dishes:</strong> Sarah Jones thought she had a good idea for a business in selling organic gourmet food online. She did not undertake any market research. She did not really know what competition she had in the gourmet online food market. She only had a general idea about the price she should be charging. There was no clear view on exactly who her customers were likely to be. Deliveries were disorganised. After a disastrous first six months Sarah had lost much of her savings in the business. Sarah would have benefited from undertaking market research before she started her business.</p>", "question": "What is market research?", "options": ["The collection of data on customer habits to help decision-making in marketing", "The advertising of a product to boost sales", "The recruitment and training of sales staff", "The process of designing and testing new packaging for a product before its launch"]}'::jsonb, '{"answer": 0, "explain": "The card defines market research as the collection of data on customer habits to help decision-making in marketing — this is what Sarah failed to do before launching her business."}'::jsonb),
('business:2-2-market-research:learn:7abce8dc', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Why is Market Research Important?", "reading": "<p>Market research will help a business be clear on whether there is <strong>demand</strong> for their product or service. Put quite simply: will customers buy the product or not? There is clearly no use making a product or providing a service if no one wants it!</p>\n<ul>\n<li><strong>Avoids unnecessary investment:</strong> If a business is considering investing lots of money into a project, it is in its own interests to make sure that there is demand — otherwise that investment will be wasted.</li>\n<li><strong>Identifies the target market:</strong> Understanding who customers are (age, gender, income, location) helps focus product development and marketing.</li>\n<li><strong>Helps with pricing:</strong> Market research can reveal what price customers are willing to pay.</li>\n<li><strong>Identifies competition:</strong> Businesses need to know who their competitors are and what they offer.</li>\n<li><strong>Helps with market segmentation:</strong> Different products can be aimed at different groups — e.g. watches come in many styles aimed at different types of customer.</li>\n</ul>\n<p><strong>Important evaluation point:</strong> Not all businesses use all types of market research. Smaller businesses may use very little, if any. Some owners rely on their own judgement. The question is always: does the business have the money and time to complete expensive research?</p>", "question": "According to this card, why does market research help avoid unnecessary investment?", "options": ["It guarantees a fixed return on any investment made", "It automatically reduces a business''s production costs", "It confirms there is demand before money is spent on a project", "It removes the need for a business to make a business plan"]}'::jsonb, '{"answer": 2, "explain": "The card explains that if a business is considering investing lots of money, research helps confirm demand exists — otherwise the investment will be wasted."}'::jsonb),
('business:2-2-market-research:learn:f5152809', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Primary Research — Questionnaires", "reading": "<p><strong>Primary research</strong> (also called ''field research'') involves collecting information that is new — gathered first-hand specifically for this business and its needs.</p>\n<p>A <strong>questionnaire</strong> is a question sheet filled in by the consumer. Questionnaires may be sent in the post, put in with guarantee forms for products, or used online to collect information from consumers.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">Cheaper than interviews to collect data</div>\n<div class=\"pro-item\">Can easily target particular consumers — e.g. a questionnaire sent with a guarantee for a product</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Difficult to predict how many completed questionnaires will be returned</div>\n<div class=\"con-item\">People filling in the forms may not understand the questions being asked</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Tip:</strong> To increase response rates, businesses sometimes offer an entry into a free prize draw to encourage consumers to complete and return the questionnaire.</p>", "question": "According to this card, what is a key disadvantage of using questionnaires?", "options": ["They are usually much more expensive to run and organise than face-to-face interviews", "They cannot be used to target specific consumers", "They cannot be completed online", "It is difficult to predict how many completed questionnaires will be returned"]}'::jsonb, '{"answer": 3, "explain": "The card lists as a disadvantage that it is difficult to predict how many completed questionnaires will be returned — unlike interviews, which are described as more expensive."}'::jsonb),
('business:2-2-market-research:learn:66a6e04b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Primary Research — Interviews", "reading": "<p>In an <strong>interview</strong>, customers are asked questions and the person asking (the interviewer) fills in the answers. Group interviews are sometimes used where a group of customers are asked the same questions at the same time. Interviews can also take place over the telephone.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">The interviewer can explain questions if there is a misunderstanding</div>\n<div class=\"pro-item\">Customers can be targeted easily — e.g. picking out certain age groups in a street to interview</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Can be expensive because an interviewer has to be paid</div>\n<div class=\"con-item\">Customers may feel uncomfortable being interviewed — whether stopped in the street or on the phone</div>\n</div>\n</div>", "question": "According to this card, what is a stated advantage of interviews over questionnaires?", "options": ["Interviews never make customers feel uncomfortable", "Interviews are usually cheaper to carry out than questionnaires or focus groups", "Interviews do not require anyone to be paid", "The interviewer can explain questions if there is a misunderstanding"]}'::jsonb, '{"answer": 3, "explain": "The card states that in an interview, the interviewer can explain questions if there is a misunderstanding, whereas questionnaires offer no such clarification."}'::jsonb),
('business:2-2-market-research:learn:736bc7fa', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Primary Research — Trials", "reading": "<p>In a <strong>trial</strong>, the product or service is sold for a short time as a test to see whether or not consumers like the product. For a large business, which might normally sell products across the UK, a trial may be set up in a much smaller area. A smaller business might simply add a new product to sell for a short period of time without buying in large quantities.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">As trials are conducted in a small area, a business may save money — just in case it finds out that customers don''t want what the business has for sale</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Trials are still costly to set up</div>\n<div class=\"con-item\">The area chosen must fully reflect the target market — if not, money will be wasted</div>\n<div class=\"con-item\">The business may conduct a trial and only find out what they first thought</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Important exam note:</strong> Trialling is about measuring whether people will BUY a product (sales figures). It is NOT about getting qualitative feedback on how to improve the product. Do not confuse trialling with giving out free samples to gain opinions.</p>", "question": "According to the exam note in this card, what does trialling a product primarily measure?", "options": ["Whether people will buy the product, shown through sales figures", "Customer opinions and feedback on how to improve the product''s design", "Staff satisfaction with the new product", "The cost of manufacturing the product"]}'::jsonb, '{"answer": 0, "explain": "The card warns that trialling is about measuring whether people will BUY a product (sales figures), not about gathering qualitative feedback to improve it."}'::jsonb),
('business:2-2-market-research:learn:d2a6f2a8', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Primary Research — Focus Groups", "reading": "<p><strong>Focus groups</strong> are small groups of people (around ten) who are carefully selected to represent the target market for a product or service. They are given information and then asked questions. The answers they give can then be analysed to provide valuable data.</p>\n<p><strong>Example:</strong> An advertising agency might show a focus group different posters that they are considering using to advertise a new product. The feedback from the focus group will then help to choose the most effective poster to use.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">Because focus groups are chosen to represent the target market, the data from them is usually very accurate and can be relied upon to make important decisions</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Though carefully chosen, they are still small groups — making data collection more expensive per person than interviews and questionnaires</div>\n<div class=\"con-item\">The selection of people to take part is time-consuming and so costly</div>\n</div>\n</div>", "question": "Why is data from focus groups usually considered accurate, according to this card?", "options": ["Focus groups are always conducted online", "Focus groups are selected to represent the target market", "They always produce quantitative data only", "Focus groups involve very large numbers of participants"]}'::jsonb, '{"answer": 1, "explain": "The card states that focus groups are chosen to represent the target market, so the data from them is usually very accurate and can be relied upon for important decisions."}'::jsonb),
('business:2-2-market-research:learn:6e9d6394', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Secondary Research — What It Is and Sources", "reading": "<p><strong>Secondary research</strong> (also called ''desk research'') is research that another organisation has already completed. A business uses information already gathered by someone else.</p>\n<p><strong>Sources of secondary research:</strong></p>\n<ul>\n<li><strong>Census data:</strong> Every person living in Britain is questioned on how they live and what their income is. Collected every ten years. Very useful for finding out how many people of a certain age or income live in a particular area. Available at www.statistics.gov.uk.</li>\n<li><strong>Websites:</strong> A huge amount of information is available on the internet. Many companies put information about themselves and their products online, which competitor businesses can use as secondary research.</li>\n<li><strong>Internal data:</strong> Many businesses have their own secondary data — past sales figures, profits from departments, and comments from customers. Usually kept on computers and used when making decisions for the future.</li>\n<li><strong>Newspapers and magazines:</strong> Full of information useful to businesses — on other businesses, trends in fashion and interests that could be used to develop new products and services. As much of this is now online, searching is easier.</li>\n</ul>", "question": "According to this card, what is secondary research?", "options": ["Research that another organisation has already completed", "Research that only comes from focus groups", "Research that is always more expensive than primary research", "Data collected first-hand for a specific business''s needs"]}'::jsonb, '{"answer": 0, "explain": "The card defines secondary (desk) research as research that another organisation has already completed, giving census data, websites, internal data and newspapers/magazines as sources."}'::jsonb),
('business:2-2-market-research:learn:876a25e1', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Advantages and Disadvantages of Secondary Research", "reading": "<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">As research has already been completed by another organisation, it is usually much <strong>cheaper</strong> to collect than primary research</div>\n<div class=\"pro-item\">A <strong>wide range</strong> of data is readily available, especially with the growth of the internet</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">The research information might <strong>not be exactly</strong> what a business wants — someone else has designed and collected it</div>\n<div class=\"con-item\">The data may <strong>not be up to date</strong> — e.g. the census is only every ten years</div>\n<div class=\"con-item\">The data might not be in a form that the business can <strong>analyse easily</strong>. Only by designing its own research (primary) can a business be sure it is in the form it requires</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Internal data</strong> is a special type of secondary data — it comes from within the business itself (e.g. past sales figures, customer comments). This avoids the problem of data not being exactly right, as the business has already collected it for its own purposes.</p>", "question": "Why is internal data considered an especially useful type of secondary data, according to this card?", "options": ["Because it is always more up to date than the national census", "Because it is provided free by the government", "Because it is classed as primary research", "Because it comes from within the business, avoiding inaccuracy"]}'::jsonb, '{"answer": 3, "explain": "The card explains that internal data comes from within the business itself, which avoids the usual secondary research problem of data not being exactly what the business wants."}'::jsonb),
('business:2-2-market-research:learn:22cba78a', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Qualitative vs Quantitative Data", "reading": "<p><strong>Qualitative data</strong> is collected when the <em>opinion</em> of consumers is needed. Because of this, it is usually collected using primary research methods — often with interviews or focus groups (though secondary research could be used too). This data can be used to help make decisions, although it is sometimes difficult to interpret opinions. For example, someone could say they dislike a product but may still be willing to buy it for someone else.</p>\n<p><strong>Quantitative data</strong> is related to <em>facts and numbers</em>. It may be the number of products sold, or how many people eat cereals for breakfast. Quantitative data could be collected using primary or secondary research. For example, people could be asked how often they eat chocolate (not their opinion on chocolate — that would be qualitative). This data is often easier to interpret than qualitative because it is simply dealing with facts and numbers.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Qualitative</div>\n<div class=\"pro-item\"><strong>Advantage:</strong> Helps the business understand what customers are thinking and what they want</div>\n<div class=\"con-item\"><strong>Disadvantage:</strong> Information may only be provided by a limited number of people; opinions can be hard to interpret</div>\n</div>\n<div>\n<div class=\"col-head\">Quantitative</div>\n<div class=\"pro-item\"><strong>Advantage:</strong> Easy to analyse and can be gathered from a large number of people</div>\n<div class=\"con-item\"><strong>Disadvantage:</strong> Limits how much people can say about what they like or dislike — no depth of opinion</div>\n</div>\n</div>", "question": "A business asks customers how often they eat chocolate. What type of data is this, according to this card?", "options": ["Qualitative data, because it is about food preferences", "Quantitative data, because it can only be collected through focus groups", "Qualitative data, because it must be collected using primary research", "Quantitative data, because it deals with facts and numbers, not opinions"]}'::jsonb, '{"answer": 3, "explain": "The card gives this exact example — asking how often people eat chocolate is quantitative because it deals with facts and numbers, not an opinion on chocolate (which would be qualitative)."}'::jsonb),
('business:2-2-market-research:learn:f8ff796e', 'business', 'business:2-2-market-research', '2.2 Market Research', 'learn', 'mcq', 1, '{"readingTitle": "Evaluation — Choosing the Right Research Method", "reading": "<p>When choosing an appropriate method of research, there are many factors to consider:</p>\n<ul>\n<li><strong>Does the business need precise, up-to-date information?</strong> If yes → primary research is likely needed, as there may not be any suitable secondary research available.</li>\n<li><strong>Is more general data sufficient?</strong> If yes → cheaper secondary research may well be suitable.</li>\n<li><strong>Does the business have the money?</strong> Primary research is usually more expensive. Smaller businesses may rely on secondary research or use informal methods (e.g. asking friends and family).</li>\n<li><strong>What size is the business?</strong> Small businesses may use very little research. Large businesses can afford detailed primary research.</li>\n<li><strong>What is the product?</strong> Some products benefit from trials (e.g. food products); others from focus groups (e.g. advertising campaigns); others from questionnaires (e.g. general consumer preferences).</li>\n</ul>\n<p><strong>Always look at the business in the question:</strong> Is it likely to need research? Does it have the money to complete expensive research? Remember that some businesses will not complete any market research, with owners relying on their own judgement.</p>\n<p><strong>Primary vs secondary comparison:</strong> Primary research is often more useful because it can be designed for the exact needs of the business and is up to date. However, it is more expensive and time-consuming. Secondary research is cheaper and widely available but may be outdated or not tailored to the business''s specific needs.</p>", "question": "According to this card, which factor is most likely to push a small business toward secondary rather than primary research?", "options": ["Primary research being banned for small businesses", "Secondary data always being more accurate than primary data", "Limited money to spend on expensive research", "A legal requirement to always use secondary data"]}'::jsonb, '{"answer": 2, "explain": "The card notes that primary research is usually more expensive, so smaller businesses may rely on cheaper secondary research or informal methods due to limited funds."}'::jsonb),
('business:2-2-market-research:misc:6ceca29c', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think trialling means giving out free samples to get feedback on how to improve a product.</p><p><strong>✅ The correct idea:</strong> Trialling is a primary market research method that involves launching a product in a limited number of stores or a limited area for a short time. The purpose is to measure SALES FIGURES to see whether there is demand — NOT to get opinions or qualitative feedback. The only direct feedback from trialling is quantitative (sales data). Do not say trialling helps ''improve'' the product.</p>", "question": "What does trialling a product actually measure?", "options": ["Sales figures showing whether there is demand for the product", "Qualitative feedback on how to improve the design of the product", "Staff performance during the trial period", "Long-term brand loyalty among customers"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that trialling gathers improvement feedback — it is a primary method that measures quantitative sales figures to test demand."}'::jsonb),
('business:2-2-market-research:misc:1444b867', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse primary and secondary research and mix up their advantages and disadvantages.</p><p><strong>✅ The correct idea:</strong> PRIMARY research is new data collected first-hand — it is more expensive and time-consuming but specific to the business''s exact needs and up to date. SECONDARY research is data already collected by someone else — it is cheaper and widely available but may be outdated and may not be in the exact form the business requires. A simple memory trick: Primary = first-hand = field research. Secondary = second-hand = desk research.</p>", "question": "Which memory trick correctly matches research type to its source, according to this card?", "options": ["Primary is always free; secondary is always paid for", "Primary = first-hand = field research; secondary = second-hand = desk research", "Primary = data collected from competitors; secondary = data collected from customers", "Primary = desk research; secondary = field research"]}'::jsonb, '{"answer": 1, "explain": "The card gives the memory trick that primary is first-hand field research, while secondary is second-hand desk research — the reverse pairing is the common student error."}'::jsonb),
('business:2-2-market-research:misc:dc506d2e', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students state that qualitative data is ''better'' than quantitative data, or vice versa, without explaining why.</p><p><strong>✅ The correct idea:</strong> Neither is universally better — each has advantages and disadvantages depending on what the business needs. Qualitative gives rich detail and opinion but is harder to analyse. Quantitative is easy to analyse and can include large numbers of people but gives no depth of opinion. For evaluation questions, you must weigh up which is MOST USEFUL for that specific business and context, and justify your judgement.</p>", "question": "How should a student correctly evaluate qualitative vs quantitative data in an exam answer, according to this card?", "options": ["State that quantitative data is always better because it is easier and quicker to fully analyse", "Weigh up which is most useful for the specific business and context, then justify the judgement", "Avoid comparing the two types of data in evaluation answers", "State that qualitative data is always better because it gives opinions"]}'::jsonb, '{"answer": 1, "explain": "The card stresses that neither type is universally better — students must weigh up which is most useful for the specific business and context and justify their judgement."}'::jsonb),
('business:2-2-market-research:misc:429bd480', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write that the advantage of primary research is that it is ''more reliable'' without explaining why.</p><p><strong>✅ The correct idea:</strong> The key advantages of primary research are that it is (1) designed EXACTLY how the business wants, (2) collected for a specific purpose, and (3) up to date. Saying it is ''more reliable'' is too vague and will not gain marks. You must say WHY it is more reliable — because it is specifically tailored to the business''s needs and is current.</p>", "question": "Why is simply stating primary research is ''more reliable'' not enough to gain marks, according to this card?", "options": ["Because it does not explain WHY it is reliable", "Because primary research is not actually reliable", "Because examiners never award marks for reliability", "Because reliability only applies to secondary research"]}'::jsonb, '{"answer": 0, "explain": "The card explains that the statement is too vague — students must explain WHY primary research is more reliable, i.e. it is designed exactly for the business and is current."}'::jsonb),
('business:2-2-market-research:misc:0c37d616', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse the terms ''qualitative'' and ''quantitative'' in answers.</p><p><strong>✅ The correct idea:</strong> Remember: QUALITATIVE = quality of opinions (think: ''qual'' as in quality, feelings, views). QUANTITATIVE = quantity, numbers, facts (think: ''quant'' as in quantity). A useful exam check: if your ''qualitative'' example involves a number or percentage, you have probably confused the two terms.</p>", "question": "What memory device does this card give to help distinguish qualitative from quantitative data?", "options": ["Quantitative always refers to focus group data", "QUALitative = numbers; QUANTitative = opinions", "QUALitative = QUALity of opinions; QUANTitative = QUANTity/numbers", "Qualitative data always refers to census data collected by the government"]}'::jsonb, '{"answer": 2, "explain": "The card gives the memory device that QUALitative relates to QUALity of opinions/feelings, while QUANTitative relates to QUANTity/numbers and facts."}'::jsonb),
('business:2-2-market-research:misc:2ada89e5', 'business', 'business:2-2-market-research', '2.2 Market Research', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think all businesses must use primary research and that secondary research is always inferior.</p><p><strong>✅ The correct idea:</strong> This is wrong. The choice of research depends on the business''s circumstances. Secondary research is often the best starting point and may be all a business needs — especially if it is small, lacks funds, or needs general data. For evaluation questions, always consider the TYPE and SIZE of the business. A small business opening a local café may get all the information it needs from census data, websites and local newspapers — without spending money on expensive primary research.</p>", "question": "A small business opening a local café needs general information about its area. What does this card say it should likely do?", "options": ["Avoid market research altogether since it is only a café", "Always commission expensive primary research regardless of budget", "Use only qualitative focus group data", "Rely on secondary research such as census data and websites"]}'::jsonb, '{"answer": 3, "explain": "The card''s example states a small local café may get all the information it needs from secondary sources like census data, websites and local newspapers, without paying for primary research."}'::jsonb),
('business:2-2-market-research:tips:6c184bc7', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tips', 'mcq', 1, '{"readingTitle": "Identify (1 mark) — Identify a Primary or Secondary Market Research Method", "reading": "<p>Simply name the method — one word or short phrase is enough. No explanation needed for 1 mark.</p>\n<ul>\n<li><strong>Primary methods:</strong> Questionnaire, interview, trial/trialling, focus group, observation</li>\n<li><strong>Secondary methods:</strong> Census, websites, newspapers, magazines, internal data, government publications, trade journals</li>\n</ul>\n<p><strong>Common errors:</strong> Writing ''survey'' as a secondary source (it is primary). Writing ''customer reviews'' or ''forums'' — examiners do not accept these as standalone answers. Do not give the TYPE of data (e.g. ''sales figures'') as a source — name the SOURCE (e.g. ''internal data'' or ''websites'').</p>", "question": "According to this card, which is a common error students make when identifying research sources?", "options": ["Writing ''trial'' as a primary source", "Writing ''websites'' as a secondary source instead of a primary one", "Writing ''census'' as a secondary source", "Writing ''survey'' as a secondary source when it''s actually primary"]}'::jsonb, '{"answer": 3, "explain": "The card lists as a common error writing ''survey'' as a secondary source, when a survey/questionnaire is actually a primary research method."}'::jsonb),
('business:2-2-market-research:tips:bdd187a1', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tips', 'mcq', 1, '{"readingTitle": "Explain (2 marks) — Explain What is Meant by [Market Research Term]", "reading": "<p>Structure: Knowledge (1) + Understanding through example or further explanation (1)</p>\n<ul>\n<li>Define the term clearly in your own words</li>\n<li>Give an example OR add further detail that shows understanding</li>\n</ul>\n<p><strong>Example — Focus group:</strong> \"A focus group is a small group of people (1) who are asked to give their views about a product or service being developed (1).\"</p>\n<p><strong>Example — Market research:</strong> \"Market research is the collection of data on customer habits (1) — for example using questionnaires or interviews — to help a business make decisions about its products and services (1).\"</p>", "question": "What two-part structure is required to gain full marks on a 2-mark ''explain'' question, according to this card?", "options": ["A judgement (1) plus a justification (1)", "Application (1) + Analysis (1)", "Knowledge (1) + Understanding (1)", "Two separate definitions of the exact same term"]}'::jsonb, '{"answer": 2, "explain": "The card states the structure is Knowledge (1) — defining the term — plus Understanding (1) shown through an example or further explanation."}'::jsonb),
('business:2-2-market-research:tips:68b2d43a', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analyse One Advantage/Benefit of a Market Research Method", "reading": "<p>Structure: Understanding (1) → Application to the specific business (1) → Business-facing Analysis (1)</p>\n<ul>\n<li>State a clear advantage/benefit of the method</li>\n<li>Apply it to the named business using case study details</li>\n<li>Explain the business impact — e.g. better decision-making, reduced risk, increased revenue, more profit</li>\n</ul>\n<p><strong>Example (EDF, focus groups):</strong> \"EDF can carefully select a focus group from customers that reflect its target market (U), for example customers who want green energy (APP). This should provide accurate information on what potential customers want, which EDF can use to make better decisions and reduce the risk of launching a service that customers do not need (AN).\"</p>\n<p><strong>Common error:</strong> Do not just describe WHAT the method is — state the BENEFIT to the business, then analyse the IMPACT on the business.</p>", "question": "What common error does this card highlight for 3-mark ''analyse'' questions on market research methods?", "options": ["Describing WHAT the method is, not its benefit and impact", "Writing too much application and not enough knowledge", "Forgetting to mention the business''s competitors", "Not naming the research method at all"]}'::jsonb, '{"answer": 0, "explain": "The card warns not to just describe what the method is — students must state the benefit to the business and then analyse the impact, following Understanding → Application → Analysis."}'::jsonb),
('business:2-2-market-research:tips:a6b03763', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (7–9 marks) — Evaluate Whether to Use Primary or Secondary Market Research", "reading": "<p>The highest mark questions require: Application (2) + Analysis (2) + Evaluation with justified judgement (3)</p>\n<ul>\n<li>Use TWO details from the case study in relation to the pros/cons of the research methods</li>\n<li>Give TWO different advantages or disadvantages of primary and/or secondary research, business-facing</li>\n<li>Make a clear decision — which type should the business use?</li>\n<li>Justify using a contextual reason from the case study (strong justification = 2 extra marks)</li>\n</ul>\n<p><strong>Exemplar response (Sainsbury''s):</strong> \"Utilising primary market research means they can find out specific information (AN) about sales in its competitive market (APP), so that Sainsbury''s can fulfil the needs and wants of its middle to high income customers (APP). Using secondary market research is much cheaper (AN). However, since Sainsbury''s is one of the largest UK supermarkets (APP), financial constraints are unlikely to be a problem. I think Sainsbury''s should use primary market research (EVAL) in future because it needs specific information to help the company develop and market products to compete with rivals like Aldi (contextual EVAL).\"</p>", "question": "What must a top-mark evaluation answer on primary vs secondary research include, according to this card?", "options": ["The examiner''s own opinion on which method is best", "Two case details, plus a clear, justified judgement", "Only a definition of primary and secondary research", "A list of every research method available to the business"]}'::jsonb, '{"answer": 1, "explain": "The card states the highest marks require application (2) and analysis (2) using case-study details, plus a justified judgement using a contextual reason for full evaluation marks."}'::jsonb),
('business:2-2-market-research:tips:a5dcce3d', 'business', 'business:2-2-market-research', '2.2 Market Research', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (9 marks — Case Study) — Evaluate Whether Market Research Shows a Business Should Go Ahead", "reading": "<p>Structure: Knowledge (1) + Understanding (1) + Application with data (2) + Analysis of impact (2) + Evaluation: judgement + justification (3)</p>\n<ul>\n<li><strong>Knowledge:</strong> Define market research</li>\n<li><strong>Understanding:</strong> Give an example of a market research method</li>\n<li><strong>Application:</strong> Use numerical data from the case study — make TWO separate points with data</li>\n<li><strong>Analysis:</strong> Explain the effect/impact on the business of the data — TWO separate points</li>\n<li><strong>Evaluation:</strong> Make a clear judgement (should they go ahead or not?), then justify using precise data from the case study</li>\n</ul>\n<p><strong>Key tip:</strong> For the evaluation justification marks, you MUST use (not simply repeat) information from the case study. The justification must clearly explain WHY the data leads you to your judgement.</p>", "question": "According to this card''s key tip, what must students do to gain evaluation justification marks?", "options": ["Use, not repeat, case data to explain the judgement", "Simply repeat the numbers given in the case study", "Avoid using any case study data in the evaluation", "State a judgement without needing a justification"]}'::jsonb, '{"answer": 0, "explain": "The card''s key tip states that for justification marks, students MUST use (not simply repeat) case study information and clearly explain why the data leads to their judgement."}'::jsonb),
('business:2-2-market-research:fib:bcd5e817', 'business', 'business:2-2-market-research', '2.2 Market Research', 'fib', 'fib', 2, '{"question": "Market research is the collection of _____ on customer habits to help decision-making in _____.", "blankOptions": {"B1": ["data", "facts", "market", "twenty"], "B2": ["facts", "secondary", "marketing", "up"]}}'::jsonb, '{"blanks": {"B1": "data", "B2": "marketing"}}'::jsonb),
