('business:2-2-market-research:fib:2aa5dd75', 'business', 'business:2-2-market-research', '2.2 Market Research', 'fib', 'fib', 2, '{"question": "The census is collected every _____ years. It is a useful source of _____ research for businesses planning where to locate or who to target.", "blankOptions": {"B1": ["expensive", "ten", "cheaper", "twenty"], "B2": ["information", "secondary", "opinions", "twenty"]}}'::jsonb, '{"blanks": {"B1": "ten", "B2": "secondary"}}'::jsonb),
('business:2-2-market-research:match:c1aa9347', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market research”?", "options": ["Data collected first-hand, often in the form of surveys, interviews, trials or focus groups — also called field research", "Data collected using research or information provided by others, such as magazines, journals and the internet — also called desk research", "The collection of data on customer habits to help decision-making in marketing", "Data based on the opinions of those being asked — e.g. why someone likes or dislikes a product"]}'::jsonb, '{"answer": 2, "explain": "“Market research” means: The collection of data on customer habits to help decision-making in marketing"}'::jsonb),
('business:2-2-market-research:match:10e0da1e', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Primary research”?", "options": ["Data collected using research or information provided by others, such as magazines, journals and the internet — also called desk research", "Data based on the opinions of those being asked — e.g. why someone likes or dislikes a product", "Data collected first-hand, often in the form of surveys, interviews, trials or focus groups — also called field research", "Data collected that is based on facts or numbers — usually easier to analyse than qualitative data"]}'::jsonb, '{"answer": 2, "explain": "“Primary research” means: Data collected first-hand, often in the form of surveys, interviews, trials or focus groups — also called field research"}'::jsonb),
('business:2-2-market-research:match:02da0683', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Secondary research”?", "options": ["Data based on the opinions of those being asked — e.g. why someone likes or dislikes a product", "Data collected that is based on facts or numbers — usually easier to analyse than qualitative data", "Data collected using research or information provided by others, such as magazines, journals and the internet — also called desk research", "A selected small group of customers (around ten) who give their opinion on products or services"]}'::jsonb, '{"answer": 2, "explain": "“Secondary research” means: Data collected using research or information provided by others, such as magazines, journals and the internet — also called desk research"}'::jsonb),
('business:2-2-market-research:match:e19a1ca4', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Qualitative data”?", "options": ["Data based on the opinions of those being asked — e.g. why someone likes or dislikes a product", "Data collected that is based on facts or numbers — usually easier to analyse than qualitative data", "A selected small group of customers (around ten) who give their opinion on products or services", "Used to test whether customers will buy a product by selling it in a limited area or for a short period"]}'::jsonb, '{"answer": 0, "explain": "“Qualitative data” means: Data based on the opinions of those being asked — e.g. why someone likes or dislikes a product"}'::jsonb),
('business:2-2-market-research:match:7387d22c', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quantitative data”?", "options": ["A selected small group of customers (around ten) who give their opinion on products or services", "Used to test whether customers will buy a product by selling it in a limited area or for a short period", "Data collected that is based on facts or numbers — usually easier to analyse than qualitative data", "Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live"]}'::jsonb, '{"answer": 2, "explain": "“Quantitative data” means: Data collected that is based on facts or numbers — usually easier to analyse than qualitative data"}'::jsonb),
('business:2-2-market-research:match:9a135158', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Focus group”?", "options": ["Used to test whether customers will buy a product by selling it in a limited area or for a short period", "Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live", "A selected small group of customers (around ten) who give their opinion on products or services", "Data already within a business based on past performance — e.g. past sales figures, customer comments"]}'::jsonb, '{"answer": 2, "explain": "“Focus group” means: A selected small group of customers (around ten) who give their opinion on products or services"}'::jsonb),
('business:2-2-market-research:match:e687708a', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trial”?", "options": ["Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live", "Used to test whether customers will buy a product by selling it in a limited area or for a short period", "Data already within a business based on past performance — e.g. past sales figures, customer comments", "The group of customers to whom a business aims to sell its products or services"]}'::jsonb, '{"answer": 1, "explain": "“Trial” means: Used to test whether customers will buy a product by selling it in a limited area or for a short period"}'::jsonb),
('business:2-2-market-research:match:a93bfe59', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Census data”?", "options": ["Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live", "Data already within a business based on past performance — e.g. past sales figures, customer comments", "The group of customers to whom a business aims to sell its products or services", "The collection of data on customer habits to help decision-making in marketing"]}'::jsonb, '{"answer": 0, "explain": "“Census data” means: Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live"}'::jsonb),
('business:2-2-market-research:match:448a2ed7', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Internal data”?", "options": ["Data already within a business based on past performance — e.g. past sales figures, customer comments", "The group of customers to whom a business aims to sell its products or services", "The collection of data on customer habits to help decision-making in marketing", "Data collected first-hand, often in the form of surveys, interviews, trials or focus groups — also called field research"]}'::jsonb, '{"answer": 0, "explain": "“Internal data” means: Data already within a business based on past performance — e.g. past sales figures, customer comments"}'::jsonb),
('business:2-2-market-research:match:bf03d39d', 'business', 'business:2-2-market-research', '2.2 Market Research', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Target market”?", "options": ["The group of customers to whom a business aims to sell its products or services", "The collection of data on customer habits to help decision-making in marketing", "Data collected first-hand, often in the form of surveys, interviews, trials or focus groups — also called field research", "Data collected using research or information provided by others, such as magazines, journals and the internet — also called desk research"]}'::jsonb, '{"answer": 0, "explain": "“Target market” means: The group of customers to whom a business aims to sell its products or services"}'::jsonb),
('business:2-3-market-segmentation:exam:72c14ee0', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'exam', 'mcq', 1, '{"num": "Q3", "question": "The owner of a toy shop wishes to use market segmentation to target customers. What is an example of market segmentation?", "options": ["Encouraging customers into the shop by posting on social media", "Opening a second toy shop in the same town", "Organising the toys in the shop by age group", "Viewing a rival store''s website to identify its special offers"], "hint": "Market segmentation is about dividing customers into groups based on their characteristics. Which option divides customers into groups?", "starter": "Market segmentation divides customers by..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — Organising the toys in the shop by age group.</strong></p><p>Organising toys by age group divides the market (toy buyers) into segments based on age — a clear example of market segmentation. Option A is a promotion/social media activity. Option B is a growth strategy. Option D is competitor research.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-3-market-segmentation:exam:65c7bd54', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Which of the following is a benefit to a business of advertising on local radio?", "options": ["Can target a specific geographical area", "Detailed financial information can be included", "Free samples can be given out with the advertisement", "The product can be seen and demonstrated"], "hint": "Think about what is UNIQUE about LOCAL radio compared to other forms of advertising.", "starter": "Local radio allows a business to..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: A — Can target a specific geographical area.</strong></p><p>Local radio is listened to by people in a specific geographical area — this links directly to location-based segmentation. Option B is not possible on radio (audio only). Option C relates to in-store sampling. Option D relates to TV or video where the product can be visually demonstrated.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-3-market-segmentation:mcq:018b7d89', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Segmentation is:", "options": ["Splitting the number of products you sell each year", "Splitting the market for a product into different parts", "Splitting the staff in a business so they produce goods quicker", "Splitting the holidays that staff take so not all staff are away at the same time"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Market segmentation is the splitting of the market for a product or service into different parts, or segments. The other options describe entirely different business activities unrelated to marketing."}'::jsonb),
('business:2-3-market-segmentation:mcq:aa22fc90', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a method of segmentation?", "options": ["Gender", "Target", "Income", "Age"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: D — Target. ''Target'' is not a method of segmentation — it is what a business does AFTER it has segmented the market (i.e. it targets a specific segment). The methods of segmentation are age, gender, income, location and lifestyle."}'::jsonb),
('business:2-3-market-segmentation:mcq:3304f871', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Segmentation of a market is done to help with:", "options": ["Targeting advertising more accurately", "Increasing the amount of products being made", "Improving the quality of goods being sold", "Making sure that workers are happy at work"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Segmentation is done so that a business can target its advertising more accurately at the specific group of customers most likely to buy the product. Options B, C and D relate to operations, quality management, and HR respectively — not marketing or segmentation."}'::jsonb),
('business:2-3-market-segmentation:mcq:8646bd0d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "It is better for a business to target a particular market because it:", "options": ["Helps them recruit staff", "Saves time in replacing stock on shelves", "Can help them to decide where to advertise", "Can help them decide whether or not it is the right time to expand the business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Targeting a particular market (segment) can help a business decide where to advertise — for example, advertising running trainers in a running magazine rather than a general interest magazine. Options A, B and D are not benefits of market segmentation."}'::jsonb),
('business:2-3-market-segmentation:mcq:72c14ee0', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "The owner of a toy shop wishes to use market segmentation to target customers. What is an example of market segmentation?", "options": ["Encouraging customers into the shop by posting on social media", "Opening a second toy shop in the same town", "Organising the toys in the shop by age group", "Viewing a rival store''s website to identify its special offers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Organising toys by age group is an example of market segmentation — the market (toy buyers) is being divided into segments based on the age of children. Options A and B are promotion/growth strategies. Option D is competitive analysis, not segmentation."}'::jsonb),
('business:2-3-market-segmentation:mcq:65c7bd54', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit to a business of advertising on local radio?", "options": ["Can target a specific geographical area", "Detailed financial information can be included", "Free samples can be given out with the advertisement", "The product can be seen and demonstrated"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Local radio allows a business to target a specific geographical area — this links to location-based segmentation. Option B is not possible on radio (audio only). Option C relates to in-store sampling. Option D relates to TV or video advertising where the product can be shown."}'::jsonb),
('business:2-3-market-segmentation:mcq:5146b092', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes the term ''target market''?", "options": ["All the people who might ever buy any product", "The group of customers at which a product or service is aimed", "A goal set by the marketing department to increase sales", "The price level a business targets for its products"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A target market is the group of customers at which a product or service is specifically aimed or targeted. It is identified through market segmentation — dividing the market and then selecting the most appropriate segment to focus on."}'::jsonb),
('business:2-3-market-segmentation:mcq:9010a66d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "Adidas segments its market by different sports, footwear/clothing, male/female, and budget/professional products. Which segmentation method does ''budget vs professional products'' best represent?", "options": ["Gender", "Location", "Age", "Income"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: C — Income. Budget products are aimed at customers with lower incomes or those less willing to spend heavily, while professional products are aimed at those with higher incomes or greater willingness to spend on premium products. This is income-based segmentation."}'::jsonb),
('business:2-3-market-segmentation:mcq:ba0a3892', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "A clothing business notices that city workers tend to buy formal suits while people in rural areas tend to buy outdoor wear. What type of market segmentation does this represent?", "options": ["Age", "Lifestyle", "Gender", "Location"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Location. The segmentation is based on where customers live and the different needs that come from their location (city vs. countryside). Location segmentation recognises that consumers in different parts of the country have different tastes and practical needs."}'::jsonb),
('business:2-3-market-segmentation:mcq:ecc7d219', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'mcq', 'mcq', 1, '{"question": "A business is considering using market segmentation for the first time. Which of the following is a potential disadvantage?", "options": ["Products will be better targeted at customer needs", "Advertising will be more focused and less wasteful", "Different promotional campaigns will be needed for different groups, increasing costs", "The business will be able to identify gaps in the market"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A disadvantage of market segmentation is that different promotional campaigns may be needed for different groups, which increases promotional costs. Options A, B and D are all advantages of market segmentation."}'::jsonb),
('business:2-3-market-segmentation:tf:b3f87ae0', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "Market segmentation means splitting the market for a product into different parts."}'::jsonb, '{"answer": true, "explain": "TRUE. Market segmentation is the splitting of the market for a product or service into different parts, or segments. This helps a business identify its target market more effectively."}'::jsonb),
('business:2-3-market-segmentation:tf:2e6e839d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "''Target'' is a valid method of market segmentation."}'::jsonb, '{"answer": false, "explain": "FALSE. ''Target'' is NOT a method of segmentation — it is what a business does AFTER it has segmented the market (i.e. it targets a specific segment). The methods are: Age, Gender, Income, Location and Lifestyle."}'::jsonb),
('business:2-3-market-segmentation:tf:aa41c3cc', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "A business that uses market segmentation can target its advertising more accurately."}'::jsonb, '{"answer": true, "explain": "TRUE. With good segmentation, a business knows exactly who its customers are and can direct advertising at the specific group most likely to buy. For example, Adidas advertises serious running trainers in running magazines rather than general interest magazines."}'::jsonb),
('business:2-3-market-segmentation:tf:9ccda65d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "A disadvantage of market segmentation is that different promotional campaigns may be needed for different groups, increasing costs."}'::jsonb, '{"answer": true, "explain": "TRUE. One disadvantage of segmentation is that different advertisements and promotions may be needed for each customer group, which increases promotional costs. This is why segmentation requires careful cost-benefit analysis."}'::jsonb),
('business:2-3-market-segmentation:tf:1f79caab', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "Market segmentation is only useful for large businesses with big marketing budgets."}'::jsonb, '{"answer": false, "explain": "FALSE. Segmentation can be used in any business situation — all businesses target their market in some way. However, it is generally MORE important to businesses with a larger amount of money to spend on advertising, as they have more to gain from ensuring that spend is well-targeted."}'::jsonb),
('business:2-3-market-segmentation:tf:b95e4a51', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "Segmenting the market by location recognises that consumers in different areas may have different needs and tastes."}'::jsonb, '{"answer": true, "explain": "TRUE. Location segmentation recognises that consumers in different parts of the country have different tastes and practical needs. For example, city workers may need business suits while those in the countryside may want outdoor clothing. A shop''s stock is often chosen to match the expected local population."}'::jsonb),
('business:2-3-market-segmentation:tf:c2e4c0e2', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "Lifestyle segmentation is based solely on a customer''s income level."}'::jsonb, '{"answer": false, "explain": "FALSE. Lifestyle segmentation is based on customers'' HOBBIES and INTERESTS — e.g. cycling, diving, fitness, following celebrities. Income segmentation is a separate method based on how much money customers earn. The two may sometimes overlap (e.g. sailing can require both an appropriate lifestyle and high income) but they are distinct methods."}'::jsonb),
('business:2-3-market-segmentation:tf:68bd61e4', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "When a business segments by income, it is typically looking to identify which customers have more money to spend on premium products."}'::jsonb, '{"answer": true, "explain": "TRUE. Income segmentation is often used to target wealthier customers who will buy premium, luxury goods — e.g. Patek Philippe watches, yachts, certain designer cars. Businesses target these customers because there could be a lot of profit to be made."}'::jsonb),
('business:2-3-market-segmentation:tf:6fe31867', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "Market segmentation can help a business identify gaps in the market that are not currently being targeted."}'::jsonb, '{"answer": true, "explain": "TRUE. By studying segments carefully, a business may identify customer groups whose needs are not currently being met by any existing product or business. This represents a market gap — an opportunity to introduce a new product or service."}'::jsonb),
('business:2-3-market-segmentation:tf:7ad5a3d2', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tf', 'tf', 1, '{"question": "For a business selling products to both serious athletes and casual wearers, using the same advertising in the same places for both products is the best approach."}'::jsonb, '{"answer": false, "explain": "FALSE. Different segments require different advertising approaches. Serious athletes might be reached through specialist sports magazines or sports events, while casual wearers might be reached through general interest media or social media. Using the same advertising for both would be inefficient and wasteful — good segmentation allows a business to target each group precisely."}'::jsonb),
('business:2-3-market-segmentation:learn:662322c6', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "What is Market Segmentation?", "reading": "<p><strong>Market segmentation</strong> is the splitting of the market for a product or service into different parts, or segments.</p>\n  <p>Splitting the market into different segments helps the business to identify its <strong>target market</strong> more effectively. This is done by looking at the different types of customers that might buy the product — their age, gender, income, location and lifestyle.</p>\n  <p>For example, Adidas will have trainers made for serious runners, and trainers made for simple everyday wear. The trainers for serious runners would be advertised in running magazines, whereas the more general trainers would not. With good segmentation, the advertising for a product can be much more accurate.</p>\n  <p>Businesses need to know that people in different segments often want different kinds of products or services — so they can target their products at the different needs of customers in each segment.</p>\n  <p>When a business targets the different segments in its market, it will need to consider:</p>\n  <ul>\n  <li><strong>Whether to produce different products</strong> for different markets — e.g. male/female versions, or basic and more sophisticated models</li>\n  <li><strong>What price to charge</strong> — high or low?</li>\n  <li><strong>How to promote the products</strong> — the type of media to use and what message this method may give</li>\n  <li><strong>Where to locate shops</strong> — town centre, shopping mall, holiday resort — and whether to sell online or not</li>\n  </ul>", "question": "What is market segmentation?", "options": ["Splitting the market for a product into different parts", "Splitting a business into separate departments", "Splitting the production process into separate stages", "Splitting company profits between shareholders"]}'::jsonb, '{"answer": 0, "explain": "Market segmentation is defined as the splitting of the market for a product or service into different parts, or segments, to identify the target market more effectively."}'::jsonb),
('business:2-3-market-segmentation:learn:2daa60cb', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "Segmentation by Age", "reading": "<p>Different age groups will buy different products. While the latest technology may be aimed at younger people, it is not to say that some older people will not also buy such products.</p>\n  <p>Recent changes in the population structure of the UK have meant there is a growing number of older people who have the wealth, health and time to enjoy themselves. This has resulted in holiday businesses targeting more (and often more expensive) holidays at this age group.</p>\n  <p><strong>Examples of age segmentation:</strong></p>\n  <ul>\n  <li>Magazines aimed at teenage girls vs. magazines aimed at women in the 20–40 age range</li>\n  <li>Bright, big and colourful watches for younger people vs. more understated designs for older people</li>\n  <li>Toys targeted at specific age bands (e.g. 0–2, 3–5, 6–10)</li>\n  <li>Holidays to Disneyland (families with young children) vs. river cruising (older customers)</li>\n  </ul>\n  <p><strong>Note:</strong> Age segmentation can be difficult to plan with total accuracy — not every young person wants the same thing, and older people may sometimes want products typically associated with younger age groups.</p>", "question": "What is a key limitation of segmenting a market by age?", "options": ["Not everyone in an age group wants the same specific products", "Age segmentation is not legally allowed for most consumer products", "It is impossible for businesses to find out the age of their customers", "Age segmentation can only be used by holiday and travel businesses"]}'::jsonb, '{"answer": 0, "explain": "The card notes that age segmentation can be difficult to plan with total accuracy, since not every young person wants the same thing and older people may want products typically aimed at younger groups."}'::jsonb),
('business:2-3-market-segmentation:learn:46bbce67', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "Segmentation by Gender, Income & Location", "reading": "<p><strong>Gender:</strong> Men and women will often (but not always) buy different products. As with age, it can be difficult to segment all products clearly. Clothing is more easily segmented along gender lines. Many businesses make products for both men and women — for example, Adidas produces sportswear for both genders.</p>\n  <p><strong>Examples:</strong> Different coloured running shoes for men and women; male/female clothing ranges.</p>\n  <p><strong>Income:</strong> People with higher levels of income will want particular products, often to show that they have wealth. This could include selected watches, yachts, certain cars, particular designer clothes. Businesses target these customers because there could be a lot of profit to be made.</p>\n  <p><strong>Examples:</strong> Patek Philippe watches for the very wealthy; Casio watches for low-income customers. Luxury garden furniture vs. budget table-and-chair sets.</p>\n  <p><strong>Location:</strong> Consumers living in different parts of the country will have different tastes and needs. If customers live in an expensive area, their tastes in products may be at the more luxury level. Another aspect is practicality — those living in a city may want a smaller car; those in the country may want a car that copes with off-road driving. The stock in a shop may be chosen to match the expected local population — a clothes shop in the country will stock different styles than those in the centre of a city.</p>\n  <p><strong>Examples:</strong> Business suits for city workers; tweed for those living in the countryside.</p>", "question": "A business designs a smaller car for city customers and a rugged off-road vehicle for rural customers. Which segmentation method does this represent?", "options": ["Location", "Age", "Income", "Gender"]}'::jsonb, '{"answer": 0, "explain": "The card explains that location segmentation considers practicality — city dwellers may want a smaller car, while those in the country may want a car that copes with off-road driving."}'::jsonb),
('business:2-3-market-segmentation:learn:7cbb64bc', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "Segmentation by Lifestyle", "reading": "<p>Different people have different hobbies and interests. This will mean that a range of products is needed to satisfy all tastes. Lifestyle may also be connected to income and location — for example, those wanting to sail a yacht may be living in a coastal location and have plenty of money.</p>\n  <p>Lifestyle can go beyond having a hobby or interest. Many people follow celebrities and wherever possible copy their lifestyle, opting for similar hairstyles and clothing. This creates demand for particular products and services that gives businesses an opportunity for profit.</p>\n  <p><strong>Examples of lifestyle segmentation:</strong></p>\n  <ul>\n  <li>Lycra clothing for the cycling enthusiast</li>\n  <li>Large flat-screen TVs for viewing enthusiasts</li>\n  <li>Special watches for diving, running and other outdoor pursuits</li>\n  <li>Specialist magazines (e.g. cycling, photography, cooking)</li>\n  <li>Health foods and gym products aimed at fitness enthusiasts</li>\n  </ul>\n  <p><strong>Adidas ''Own the Game'' strategy (2021):</strong> Adidas describes their customers as: ''They strive to live active and healthy lives, they wish to blend sport and lifestyle, they are digital by default and sustainable by conviction.'' This is a lifestyle-based segmentation approach.</p>", "question": "Adidas''s ''Own the Game'' strategy describes customers as wanting to ''blend sport and lifestyle'' and being ''sustainable by conviction''. Which segmentation method does this best represent?", "options": ["Lifestyle", "Location", "Age", "Income"]}'::jsonb, '{"answer": 0, "explain": "The card states that Adidas''s description of customers by their interests and way of living is a lifestyle-based segmentation approach."}'::jsonb),
('business:2-3-market-segmentation:learn:3619004d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "Advantages and Disadvantages of Market Segmentation", "reading": "<div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages</div>\n  <div class=\"pro-item\"><strong>Increased sales:</strong> Can design and produce products specifically aimed at groups of customers — more likely to meet their needs and be purchased</div>\n  <div class=\"pro-item\"><strong>Helps identify gaps in the market:</strong> By studying segments, a business can identify customer groups that are not currently being targeted</div>\n  <div class=\"pro-item\"><strong>Avoids wasting money:</strong> Marketing will be focused on the specific target group rather than a broad, general audience</div>\n  <div class=\"pro-item\"><strong>Higher market share:</strong> By meeting specific needs, a business can win loyal customers from that segment</div>\n  <div class=\"pro-item\"><strong>Better targeted advertising:</strong> If a business is clear on its market (due to segmentation), it can target advertising much more accurately — greater return on marketing expenditure</div>\n  <div class=\"pro-item\"><strong>Improved customer retention:</strong> Products that closely meet customer needs lead to greater satisfaction and repeat purchases</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages</div>\n  <div class=\"con-item\"><strong>High promotional costs:</strong> Different advertisements and promotions may be needed for different groups</div>\n  <div class=\"con-item\"><strong>Cost of market research:</strong> Research to identify and understand each specific segment can be expensive</div>\n  <div class=\"con-item\"><strong>Lack of information:</strong> Some markets are poorly researched and data may be limited or unreliable</div>\n  <div class=\"con-item\"><strong>Hard to reach segments:</strong> Some customer groups are difficult to target effectively with existing marketing channels</div>\n  <div class=\"con-item\"><strong>Difficulty of clear segmentation:</strong> Not all products can be clearly segmented — e.g. not every young person wants the same things</div>\n  </div>\n  </div>", "question": "Which of the following is a disadvantage of market segmentation?", "options": ["Different promotional campaigns are needed per group", "It helps a business identify gaps in the market", "It leads to better-targeted advertising", "It can increase market share by winning loyal customers"]}'::jsonb, '{"answer": 0, "explain": "The card lists high promotional costs — needing different advertisements and promotions for different groups — as a key disadvantage of market segmentation."}'::jsonb),
('business:2-3-market-segmentation:learn:708e76ca', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'learn', 'mcq', 1, '{"readingTitle": "Evaluation — Is Segmentation Worth It?", "reading": "<p>Segmentation can be used in any business situation. All businesses target their market in some way. When evaluating, look for the ways in which the market for a business can be split and how this splitting, or segmentation, will benefit the business.</p>\n  <p><strong>Segmentation is generally more important to businesses which have:</strong></p>\n  <ul>\n  <li>A larger amount of money to spend on advertising</li>\n  <li>A diverse product range targeting different customer groups</li>\n  <li>A need to differentiate themselves from competitors</li>\n  </ul>\n  <p><strong>Case study — Adidas:</strong> Adidas has a carefully segmented market: different sports (football, athletics, golf), different needs (footwear, clothing), male and female markets, and budget and professional products. This segmentation has been central to Adidas growing from a small German business into a global brand.</p>\n  <p><strong>Case study — Amala''s Garden Furniture:</strong> Amala''s business makes luxury sets (costing thousands of pounds) alongside small sets (under £100). Using market segmentation would help the business decide the income range at which to target each range, and where to advertise — e.g. luxury products in a garden magazine vs. budget products in a local newspaper. This would make advertising more focused and save money by only advertising where it is effective.</p>\n  <p><strong>Evaluation summary:</strong> The benefits of segmentation (increased sales, better-targeted advertising, identifying gaps in the market) are likely to outweigh the costs (market research, different promotional campaigns) for most established businesses, especially those operating in competitive markets with diverse customer groups.</p>", "question": "According to the evaluation guidance, segmentation is generally MORE important to businesses that have which of the following?", "options": ["A larger advertising budget and diverse product range overall", "A single, simple product with a very small advertising budget", "Only one type of customer and no competitors", "A policy of never changing prices or products"]}'::jsonb, '{"answer": 0, "explain": "The card states segmentation is generally more important to businesses with a larger amount of money to spend on advertising and a diverse product range targeting different customer groups."}'::jsonb),
('business:2-3-market-segmentation:misc:7e51652a', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students sometimes think that a business using market segmentation wants to sell to EVERYBODY and should try to target all customers equally.</p><p><strong>✅ The correct idea:</strong> Market segmentation is specifically about dividing the market into DIFFERENT PARTS and targeting ONE or more specific segments — not everyone. The whole purpose of segmentation is to focus resources on the customers most likely to buy a product. A business that tries to target everyone at once risks wasting money on advertising that reaches people who will never buy the product.</p>", "question": "What is the true purpose of market segmentation?", "options": ["To divide the market and target specific segments", "To make sure every single customer in the whole market is targeted equally", "To reduce the number of products a business makes", "To increase the number of retail outlets a business owns"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that segmentation targets everybody equally — its real purpose is to divide the market into different parts and focus on specific segments most likely to buy."}'::jsonb),
('business:2-3-market-segmentation:misc:afc9bcaf', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often confuse ''market segmentation'' (the method) with ''target market'' (the outcome). They use the terms interchangeably.</p><p><strong>✅ The correct idea:</strong> Market segmentation is the PROCESS of splitting the market into different groups. The TARGET MARKET is the specific group of customers a business then CHOOSES to aim its products at. You segment first, then select your target market. E.g. Boohoo segmented by age and identified that its target market is 16–24 year olds who are fashion conscious.</p>", "question": "What is the correct relationship between ''market segmentation'' and ''target market''?", "options": ["Segmentation splits the market; target market is chosen afterward from it", "The two terms mean exactly the same thing and can always be used interchangeably", "The target market is decided first, and the market is segmented afterwards", "Target market refers only to customers located overseas"]}'::jsonb, '{"answer": 0, "explain": "The card clarifies that segmentation is the process of splitting the market, while the target market is the specific group a business then chooses to aim its products at — segmentation happens first."}'::jsonb),
('business:2-3-market-segmentation:misc:bd5fa5dd', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''analyse'' questions about market segmentation, students often answer by describing what segmentation is, instead of analysing its benefit or impact on the business.</p><p><strong>✅ The correct idea:</strong> Explaining WHAT segmentation is scores zero for ''analyse'' or ''explain'' questions. You need: Understanding of a benefit (1) → Application to the named business (1) → Business impact/Analysis (1). E.g. ''Segmentation allows Sainsbury''s to alter products to satisfy the specific needs of middle to high income customers (U+APP), which will help boost revenue and maintain customer loyalty in a very competitive supermarket industry (AN).''</p>", "question": "For an ''analyse'' question on the benefit of market segmentation, what must the answer include to score full marks?", "options": ["Understanding of a benefit, applied and analysed", "A definition of what market segmentation means", "A list of all five methods of segmentation", "A description of the business''s trading history"]}'::jsonb, '{"answer": 0, "explain": "The card states that simply describing what segmentation is scores zero — analyse answers need Understanding of a benefit, Application to the named business, and Analysis of the impact."}'::jsonb),
('business:2-3-market-segmentation:misc:5994a05b', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''analyse'' questions about product development and segmentation, students often mention pricing, advertising or promotion rather than the product itself.</p><p><strong>✅ The correct idea:</strong> If the question asks about market segmentation when DEVELOPING NEW PRODUCTS, your answer must focus on the PRODUCT — e.g. how segmentation helps the business create, design, tailor or alter the product to meet the needs of specific customer groups. Do NOT answer with points about pricing, advertising, or launching the product — these are post-development and will not be credited.</p>", "question": "When a question asks how market segmentation helps with DEVELOPING NEW PRODUCTS, what must the answer focus on?", "options": ["How segmentation helps design or tailor the product", "How segmentation helps set the price of the product", "How segmentation helps choose an advertising method", "How segmentation helps decide where to sell the product"]}'::jsonb, '{"answer": 0, "explain": "The card warns that for product development questions, only points about creating, designing or tailoring the product are creditworthy — pricing and advertising points will not be credited."}'::jsonb),
('business:2-3-market-segmentation:misc:97bf0ab2', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students sometimes list ''target'' as a method of market segmentation.</p><p><strong>✅ The correct idea:</strong> ''Target'' is NOT a method of segmentation — it is what a business does AFTER it has segmented the market. The methods of segmentation are: Age, Gender, Income, Location and Lifestyle. ''Target'' is the ACTION of directing your marketing at the chosen segment. Always use one of the five methods when asked to state a way to segment a market.</p>", "question": "Which of these is NOT one of the five recognised methods of market segmentation?", "options": ["Target", "Income", "Lifestyle", "Age"]}'::jsonb, '{"answer": 0, "explain": "The card explains that ''target'' is not a method of segmentation — it is the action a business takes after segmenting; the five methods are age, gender, income, location and lifestyle."}'::jsonb),
('business:2-3-market-segmentation:misc:1679781c', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''explain one way to segment a market'' questions, students often write only one word (e.g. ''age'') and think this is enough.</p><p><strong>✅ The correct idea:</strong> Writing just ''age'' scores only 1 mark (knowledge). To score the second mark (understanding), you must show HOW that method is used — e.g. ''A business could segment by age (K), for example by aiming its products specifically at elderly people or teenagers (U).'' The ''explain'' command word always requires development beyond simply naming the method.</p>", "question": "For a 2-mark ''explain one way to segment a market'' question, what does writing only ''age'' achieve?", "options": ["Only 1 mark — it needs an example for understanding", "Full marks, because naming a correct method is always enough", "Zero marks, because no explanation at all was given", "2 marks, but only if the named business is also mentioned"]}'::jsonb, '{"answer": 0, "explain": "The card states that writing just ''age'' scores only the knowledge mark; the second (understanding) mark requires showing how that method is used in practice."}'::jsonb),
('business:2-3-market-segmentation:tips:bd601458', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify (1 mark each) — State a Method of Market Segmentation", "reading": "<p>Simply name the method — no explanation needed for ''state'' or ''identify'' questions.</p>\n  <p><strong>Accepted methods:</strong> Age / Gender (sex) / Income / Location / Lifestyle</p>\n  <p><strong>NOT accepted:</strong> ''Target'' (this is not a method), ''demographic'' alone (too vague), or any reference to advertising location (e.g. ''advertise on TV'' — this is not a segmentation criterion).</p>\n  <p><strong>Special cases:</strong> ''Boys'' or ''Girls'' alone can be awarded as age OR gender. ''Boys and girls'' together counts as age only.</p>", "question": "In a ''state'' or ''identify'' question on segmentation methods, which answer would NOT be accepted?", "options": ["''Lifestyle''", "''Income''", "''Age''", "''Target''"]}'::jsonb, '{"answer": 3, "explain": "The card explicitly lists ''target'' as not accepted, since it is not a method of segmentation, unlike age, gender, income, location and lifestyle."}'::jsonb),
('business:2-3-market-segmentation:tips:98c9d174', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tips', 'mcq', 1, '{"readingTitle": "Explain (2 marks) — Explain One Way a Business Can Segment Its Market", "reading": "<p>Structure: Knowledge (1) + Understanding of how the method is used (1)</p>\n  <ul>\n  <li>Name a method of segmentation</li>\n  <li>Give an example of how it is used or what it means in practice</li>\n  </ul>\n  <p><strong>Example:</strong> \"One way a business could segment its market is by age (K), for example by aiming to sell products specifically to elderly people who have wealth and time to enjoy themselves (U).\"</p>\n  <p><strong>Example:</strong> \"By gender (K), by targeting marketing particularly at women, for example with a range of women''s clothing or beauty products (U).\"</p>\n  <p><strong>Note:</strong> Answers do not need to relate to the named business in the case study unless the question asks specifically for that.</p>", "question": "For a 2-mark ''explain one way a business can segment its market'' question, what structure is required?", "options": ["Knowledge of a method plus understanding of its use", "Knowledge only, with the same point repeated twice", "Application to the case study business plus Analysis of the impact", "A definition of segmentation followed by a judgement"]}'::jsonb, '{"answer": 0, "explain": "The card sets out the structure as Knowledge (1) — naming a method — plus Understanding (1) — an example of how the method is used."}'::jsonb),
('business:2-3-market-segmentation:tips:d4629dae', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analyse a Benefit of Using Market Segmentation", "reading": "<p>Structure: Understanding (1) → Application to the named business (1) → Business-facing Analysis (1)</p>\n  <ul>\n  <li>State a benefit of market segmentation</li>\n  <li>Apply it to the specific business using case study details</li>\n  <li>Explain the business impact — sales, revenue, customer satisfaction, market share, etc.</li>\n  </ul>\n  <p><strong>Example (Sainsbury''s — product development):</strong> \"Sainsbury''s can alter its products to satisfy the specific needs of customer segments (U). Since Sainsbury''s targets middle to high income customers in a very competitive supermarket industry (APP), tailoring products to this segment will help boost revenue and maintain customer loyalty (AN).\"</p>\n  <p><strong>Important:</strong> For questions specifically about PRODUCT DEVELOPMENT, only answers about creating/designing/tailoring the product are creditworthy. Do not answer with points about pricing or advertising.</p>", "question": "What is the correct mark structure for a 3-mark ''analyse a benefit of market segmentation'' question?", "options": ["Understanding, application, then analysis of impact", "Knowledge (1) + Understanding (1) + Evaluation (1)", "Three separate benefits, worth one mark each", "Application worth all 3 marks, with no need for understanding or analysis"]}'::jsonb, '{"answer": 0, "explain": "The card sets out the structure as Understanding (1) leading to Application to the named business (1) leading to business-facing Analysis (1)."}'::jsonb),
('business:2-3-market-segmentation:tips:15209e4f', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (6 marks — 2×3) — Analyse Two Benefits of Market Segmentation", "reading": "<p>For each benefit: Understanding (1) + Application to the named business (1) + Analysis (1).</p>\n  <p><strong>Common benefits to use:</strong></p>\n  <ul>\n  <li>Helps target specific customers / better meet customer needs</li>\n  <li>Can tailor the product/range to attract a specific group</li>\n  <li>Can design promotion/advertising campaign to target a specific group — greater return on marketing expenditure</li>\n  <li>Can adjust price/pricing strategy to attract a specific group</li>\n  <li>Can change the place/distribution channels to attract a specific group</li>\n  <li>Avoids wasting money on broad, non-targeted advertising</li>\n  <li>Identifies gaps in the market not currently being served</li>\n  </ul>\n  <p><strong>Apply using case study details</strong> — number of shops, declining sales, sole trader status, types of product, existing segmentation criteria, etc.</p>", "question": "For the 6-mark ''analyse two benefits of market segmentation'' question, how should marks be distributed?", "options": ["Each benefit is worth 3 marks: Understanding + Application + Analysis, done twice", "One combined 6-mark answer covering both benefits together without separating them", "6 marks for simply stating six different segmentation methods", "Application is worth all 6 marks, with no need for understanding or analysis"]}'::jsonb, '{"answer": 0, "explain": "The card states that for each benefit, Understanding (1) + Application to the named business (1) + Analysis (1) should be given, repeated for the second benefit."}'::jsonb),
('business:2-3-market-segmentation:tips:aa40d6bb', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (7 marks) — Evaluate the Benefit of Market Segmentation", "reading": "<p>Structure: Application (2) + Analysis (2) + Evaluation — judgement (1) + justification (2)</p>\n  <ul>\n  <li>Two applied points using case study details</li>\n  <li>Two analytical impacts on the business</li>\n  <li>A simple judgement — do you think it will benefit the business?</li>\n  <li>A justified contextual conclusion — why do you think this? Use the case study.</li>\n  </ul>\n  <p><strong>Judgement example:</strong> \"Overall, I think market segmentation will be very effective in helping Amala''s family business.\"</p>\n  <p><strong>Justified conclusion:</strong> \"The business makes a range of garden furniture from luxury sets (thousands of pounds) to small sets (under £100). It must identify just who is buying the different products so these consumers can be targeted. It is no good simply advertising all products in one place — different products require different approaches, and clear segmentation will make advertising more focused and save money.\"</p>", "question": "What must a 7-mark ''evaluate the benefit of market segmentation'' answer include beyond application and analysis?", "options": ["A judgement plus a justified conclusion using case study context", "A repeated definition of what market segmentation means", "Three further analytical points instead of a judgement", "A complete list of every segmentation method used by the business"]}'::jsonb, '{"answer": 0, "explain": "The card sets out the structure as Application (2) + Analysis (2) + a simple judgement (1) + a justified contextual conclusion (2)."}'::jsonb),
('business:2-3-market-segmentation:fib:f1a2a2ae', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "Market _____ is the splitting of the market for a product into different parts. This helps a business identify its _____ market more effectively.", "blankOptions": {"B1": ["lifestyle", "customers", "segmentation", "price"], "B2": ["different", "target", "income", "price"]}}'::jsonb, '{"blanks": {"B1": "segmentation", "B2": "target"}}'::jsonb),
('business:2-3-market-segmentation:fib:3d0ab322', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "The five main ways to segment a market are: _____, gender, income, _____ and lifestyle.", "blankOptions": {"B1": ["different", "age", "customers", "price"], "B2": ["gap", "group", "advertising", "location"]}}'::jsonb, '{"blanks": {"B1": "age", "B2": "location"}}'::jsonb),
('business:2-3-market-segmentation:fib:f0b8630e', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "With good segmentation, the _____ for a product can be much more accurate. Businesses can avoid wasting money by focusing marketing on the specific _____.", "blankOptions": {"B1": ["gap", "customers", "advertising", "sales"], "B2": ["price", "group", "lifestyle", "age"]}}'::jsonb, '{"blanks": {"B1": "advertising", "B2": "group"}}'::jsonb),
('business:2-3-market-segmentation:fib:60b3175f', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "A disadvantage of market segmentation is that _____ promotional costs may be needed for different groups. The cost of _____ research for specific segments can also be high.", "blankOptions": {"B1": ["lifestyle", "competition", "different", "sales"], "B2": ["lifestyle", "segmentation", "market", "similar"]}}'::jsonb, '{"blanks": {"B1": "different", "B2": "market"}}'::jsonb),
('business:2-3-market-segmentation:fib:747f1d10', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "People with higher levels of _____ will want particular products, often to show their wealth. People with different hobbies and interests are segmented by _____.", "blankOptions": {"B1": ["income", "gender", "group", "customers"], "B2": ["target", "advertising", "lifestyle", "similar"]}}'::jsonb, '{"blanks": {"B1": "income", "B2": "lifestyle"}}'::jsonb),
('business:2-3-market-segmentation:fib:ce27d0ec', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'fib', 'fib', 2, '{"question": "Although the Rolls Royce and the Ford Focus are both cars, they are not in _____ with each other. By segmenting the market, a business may be able to identify a _____ in the market.", "blankOptions": {"B1": ["target", "location", "competition", "advertising"], "B2": ["gap", "advertising", "segmentation", "profit"]}}'::jsonb, '{"blanks": {"B1": "competition", "B2": "gap"}}'::jsonb),
('business:2-3-market-segmentation:match:34b0e20d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market segmentation”?", "options": ["The group of customers at which a product or service is aimed or targeted", "Dividing the market based on how old customers are — e.g. targeting teenagers, over-50s, or families with young children", "Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women", "The splitting of the market for a product or service into different parts, or segments"]}'::jsonb, '{"answer": 3, "explain": "“Market segmentation” means: The splitting of the market for a product or service into different parts, or segments"}'::jsonb),
('business:2-3-market-segmentation:match:9bf57215', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Target market”?", "options": ["The group of customers at which a product or service is aimed or targeted", "Dividing the market based on how old customers are — e.g. targeting teenagers, over-50s, or families with young children", "Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners"]}'::jsonb, '{"answer": 0, "explain": "“Target market” means: The group of customers at which a product or service is aimed or targeted"}'::jsonb),
('business:2-3-market-segmentation:match:792f4cc7', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Age segmentation”?", "options": ["Dividing the market based on how old customers are — e.g. targeting teenagers, over-50s, or families with young children", "Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners", "Dividing the market based on where customers live — e.g. city vs. countryside, local vs. national"]}'::jsonb, '{"answer": 0, "explain": "“Age segmentation” means: Dividing the market based on how old customers are — e.g. targeting teenagers, over-50s, or families with young children"}'::jsonb),
('business:2-3-market-segmentation:match:6c8bb9f4', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gender segmentation”?", "options": ["Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners", "Dividing the market based on where customers live — e.g. city vs. countryside, local vs. national", "Dividing the market based on customers'' hobbies, interests and ways of living — e.g. sportswear for cyclists, specialist watches for divers"]}'::jsonb, '{"answer": 0, "explain": "“Gender segmentation” means: Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women"}'::jsonb)
